const page = figma.root.children.find(p => p.id === PAGE_ID);
await figma.setCurrentPageAsync(page);
const grid = await figma.getNodeByIdAsync(GRID_ID);

const created = [];
for (const [slug, svgStr] of Object.entries(BATCH_DATA)) {
  const svgFrame = figma.createNodeFromSvg(svgStr);
  svgFrame.name = 'art';
  const aspect = svgFrame.height / svgFrame.width;
  svgFrame.resize(TARGET_W, Math.round(TARGET_W * aspect));

  const comp = figma.createComponent();
  comp.name = 'Illustration/' + slug;
  comp.resize(svgFrame.width, svgFrame.height);
  comp.clipsContent = false;
  comp.fills = [];
  comp.appendChild(svgFrame);
  svgFrame.x = 0; svgFrame.y = 0;

  page.appendChild(comp);
  comp.x = -5000; comp.y = created.length * 400;

  const inst = comp.createInstance();
  grid.appendChild(inst);
  created.push({ slug, compId: comp.id, instId: inst.id });
}

return { added: created.length, items: created };